INSERT INTO t_p2335699_khmao_sport_events.posts (title, content, excerpt, image_url, tags, published) VALUES
('Биатлонный стадион «Югра» обновил трассу', 'Перед стартом нового соревновательного сезона биатлонный комплекс «Югра» завершил масштабную реконструкцию лыжных трасс. Установлены новые системы искусственного снегообразования, обновлена система освещения для ночных гонок. Обновлённые трассы соответствуют стандартам IBU.', 'Перед стартом сезона биатлонный комплекс «Югра» завершил масштабную реконструкцию трасс.', 'https://cdn.poehali.dev/projects/bedfc3d3-ec88-4a38-aa9b-6b3fe1ddd98d/files/af9e3b8f-159a-4186-a77f-c9d72a5783c5.jpg', ARRAY['Биатлон', 'Инфраструктура'], TRUE),
('Итоги Чемпионата ХМАО по лыжным гонкам', 'В Ханты-Мансийске завершился Чемпионат ХМАО-Югры по лыжным гонкам. В соревнованиях приняли участие более 180 спортсменов из 12 муниципальных образований округа. Победители определились в шести дисциплинах.', 'В соревнованиях приняли участие более 180 спортсменов из 12 муниципальных образований.', 'https://cdn.poehali.dev/projects/bedfc3d3-ec88-4a38-aa9b-6b3fe1ddd98d/files/0e61203e-60ee-47ee-9bc7-7db5e616c7c3.jpg', ARRAY['Лыжи', 'Итоги'], TRUE),
('Марафон «Югра»: регистрация открыта', 'Объявляем о старте регистрации на ежегодный городской марафон «Югра». В этом году ожидается участие более 1500 спортсменов. Доступные дистанции: 5 км, 10 км, полумарафон и марафон 42,2 км. Регистрация доступна на портале.', 'Регистрация на марафон «Югра» открыта. Ожидается участие более 1500 спортсменов.', NULL, ARRAY['Марафон', 'Регистрация'], TRUE);